from flask import Flask, request

app = Flask(__name__)

@app.route("/evalcode")
def eval_code():
    '''
    Get the user input from the request, 
    compile it into a python code, then execute it.
    '''
    user_code = request.args.get('code', '')
    try:
        # Compile the user input into a code object
        compiled_code = compile(user_code, '<string>', 'exec')

        # Execute the compiled code
        # Using a separate dictionary for locals to avoid polluting global namespace
        exec_globals = {}
        exec_locals = {}
        exec(compiled_code, exec_globals, exec_locals)

        return "Execution successful", 200
    except Exception as e:
        return f"Error executing code: {str(e)}", 400

import logging


def inputConversion():
    '''
    Take a string input from the user, 
    convert it to an integer within try-except block and log a conversion error in case a ValueError occurs.
    Return the converted user input.
    '''
    user_input = input("Please enter an integer: ")
    try:
        return int(user_input)
    except ValueError:
        logging.error("Conversion error: The provided input is not a valid integer.")
        return None

from OpenSSL import SSL

def getContext():
    '''
    Create an OpenSSL context and return it.
